UPDATE public.faq_articles
SET category_id = (SELECT id FROM public.faq_categories WHERE slug = 'fleet')
WHERE slug IN ('manage-vehicles', 'fleet-overview', 'vehicle-categories')
  AND category_id = (SELECT id FROM public.faq_categories WHERE slug = 'maintenance');

CREATE OR REPLACE FUNCTION pg_temp.upsert_faq_article(
  p_category_slug TEXT,
  p_title TEXT,
  p_slug TEXT,
  p_summary TEXT,
  p_content_md TEXT,
  p_sort_order INTEGER
)
RETURNS VOID
LANGUAGE plpgsql
AS $$
DECLARE
  v_category_id UUID;
BEGIN
  SELECT id INTO v_category_id
  FROM public.faq_categories
  WHERE slug = p_category_slug;

  IF v_category_id IS NULL THEN
    RAISE EXCEPTION 'FAQ category not found: %', p_category_slug;
  END IF;

  INSERT INTO public.faq_articles (
    category_id,
    title,
    slug,
    summary,
    content_md,
    is_published,
    sort_order
  )
  VALUES (
    v_category_id,
    p_title,
    p_slug,
    p_summary,
    p_content_md,
    TRUE,
    p_sort_order
  )
  ON CONFLICT (category_id, slug) DO UPDATE
  SET
    title = EXCLUDED.title,
    summary = EXCLUDED.summary,
    content_md = EXCLUDED.content_md,
    is_published = TRUE,
    sort_order = EXCLUDED.sort_order;
END;
$$;

SELECT pg_temp.upsert_faq_article(
  'getting-started',
  'What is the SQUIRES App?',
  'what-is-squires-app',
  'Overview of the SQUIRES digital work management system.',
  $md$# What is the SQUIRES App?

SQUIRES is the A&V Squires digital work management app. It replaces paper forms and shared spreadsheets with a mobile-first web app for daily site and office workflows.

## What it covers

The modules you see depend on your role and permissions. Common areas include:

- Timesheets
- Van, plant, and HGV daily checks
- Projects documents and signatures
- Absence and leave
- Maintenance, fleet, workshop tasks, and inventory
- Training records
- Approvals, reports, customers, quotes, toolbox talks, reminders, suggestions, and admin tools

## Access

Open the app at https://avsworklog.mpdee.uk and sign in with your work account.

The app works on desktop, tablet, and mobile. For regular phone or tablet use, install it from the Help page so it opens like a normal app.$md$,
  0
);

SELECT pg_temp.upsert_faq_article(
  'getting-started',
  'How do I log in?',
  'how-to-login',
  'Instructions for logging into the app.',
  $md$# How do I log in?

1. Go to https://avsworklog.mpdee.uk
2. Enter your email address
3. Enter your password
4. Click **Sign In**

## First time login

If this is your first login, an admin will have created your account and sent a temporary password. You may be asked to change that password on first login.

## Forgot password?

Ask an administrator to reset your password from User Management.$md$,
  1
);

SELECT pg_temp.upsert_faq_article(
